    77→// newWatcherBatch maps watchers to their matched events. It enables quick
    78→// events look up by watcher.
    79→func newWatcherBatch(wg *watcherGroup, evs []mvccpb.Event) watcherBatch {
    80→	if len(wg.watchers) == 0 {
    81→		return nil
    82→	}
    83→
    84→	wb := make(watcherBatch)
    85→	for _, ev := range evs {
    86→		for w := range wg.watcherSetByKey(string(ev.Kv.Key)) {
    87→			if ev.Kv.ModRevision >= w.minRev {
    88→				// don't double notify
    89→				wb.add(w, ev)
    90→			}
    91→		}
    92→	}
    93→	return wb
    94→}
